import React, { useState } from 'react';

const App = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center" id="app">
      <div className="bg-white rounded shadow-md p-4 w-96 text-black">
        <h2 className="text-lg font-bold mb-4">Login</h2>
        <input type="text" className="w-full p-2 mb-4 border border-gray-300 focus:outline-none focus:ring focus:border-blue-400" placeholder="Username" value={username} onChange={(e) => setUsername(e.target.value)} />
        <input type="password" className="w-full p-2 mb-4 border border-gray-300 focus:outline-none focus:ring focus:border-blue-400" placeholder="Password" value={password} onChange={(e) => setPassword(e.target.value)} />
        <div className="flex items-center mb-4">
          <input type="checkbox" className="mr-2" checked={rememberMe} onChange={(e) => setRememberMe(e.target.checked)} />
          <label className="text-sm">Remember me</label>
        </div>
        <button className="bg-blue-400 hover:bg-blue-500 text-white font-bold py-2 px-4 rounded" onClick={() => console.log('Login button clicked')}>Login</button>
      </div>
      <div className="flex justify-end mt-4">
        <label className="mr-2 text-sm cursor-pointer" onClick={() => setDarkMode(!darkMode)}>Dark mode</label>
        <input type="checkbox" className="mr-2" checked={darkMode} onChange={(e) => setDarkMode(e.target.checked)} />
      </div>
    </div>
  );
};

export default App;
